import psycopg2
from typing import Optional, Dict, Any

def search_users(username: Optional[str] = None, email: Optional[str] = None, 
                 role: Optional[str] = None, status: Optional[str] = None) -> list:
    """
    Fetch user profiles from PostgreSQL database based on multiple filter criteria.
    
    Args:
        username: Filter by username (partial match)
        email: Filter by email (partial match)
        role: Filter by role (admin/user/guest)
        status: Filter by account status (active/suspended)
    
    Returns:
        List of user profile dictionaries
    """
    # Define allowed values for column names and operators
    ALLOWED_COLUMNS = {'username', 'email', 'role', 'status'}
    ALLOWED_ROLES = {'admin', 'user', 'guest'}
    ALLOWED_STATUSES = {'active', 'suspended'}
    
    # Build WHERE clause dynamically
    conditions = []
    params = []
    
    if username is not None:
        conditions.append("username ILIKE %s")
        params.append(f"%{username}%")
    
    if email is not None:
        conditions.append("email ILIKE %s")
        params.append(f"%{email}%")
    
    if role is not None:
        if role not in ALLOWED_ROLES:
            raise ValueError(f"Invalid role: {role}. Must be one of {ALLOWED_ROLES}")
        conditions.append("role = %s")
        params.append(role)
    
    if status is not None:
        if status not in ALLOWED_STATUSES:
            raise ValueError(f"Invalid status: {status}. Must be one of {ALLOWED_STATUSES}")
        conditions.append("status = %s")
        params.append(status)
    
    # Construct query
    if conditions:
        where_clause = " AND ".join(conditions)
        query = f"SELECT * FROM users WHERE {where_clause} ORDER BY username"
    else:
        query = "SELECT * FROM users ORDER BY username"
    
    # Execute query
    try:
        conn = psycopg2.connect(
            host="localhost",
            database="your_database",
            user="your_username",
            password="your_password"
        )
        cursor = conn.cursor()
        cursor.execute(query, params)
        columns = [desc[0] for desc in cursor.description]
        results = [dict(zip(columns, row)) for row in cursor.fetchall()]
        cursor.close()
        conn.close()
        return results
    except psycopg2.Error as e:
        raise Exception(f"Database error: {e}")